SELECT subsections.subsection_name, water_bodies.water_body_name
FROM subsections
INNER JOIN water_bodies ON subsections.water_body_id = water_bodies.water_body_id;

SELECT subsection_id, subsection_name
FROM subsections
WHERE subsection_id NOT IN (
  SELECT subsection_id FROM monitoring_data
)
LIMIT 4;

SELECT water_body_name, water_body_type
FROM water_bodies
ORDER BY water_body_name;

SELECT COUNT(water_body_id) 
FROM water_bodies 
WHERE water_body_type = 'lake';

SELECT * 
FROM water_bodies 
WHERE water_body_id = (SELECT MAX(water_body_id) FROM water_bodies);
